class SummaryRanges {
    private TreeSet<Integer> set = new TreeSet<>();

    public SummaryRanges() {

    }

    public void addNum(int value) {
        set.add(value);
    }

    public int[][] getIntervals() {
        int[][] intervals = new int[set.size()][2];
        int index = 0;
        Integer start = null, end = null;
        for (Integer num : set) {
            if (start == null) {
                start = num;
                end = num;
            } else if (num == end + 1) {
                end = num;
            } else {
                intervals[index++] = new int[] {start, end};
                start = num;
                end = num;
            }
        }
        if (start != null) {
            intervals[index++] = new int[] {start, end};
        }
        int[][] result = new int[index][2];
        System.arraycopy(intervals, 0, result, 0, index);
        return result;
    }
}
